import scala.xml.XML
import scala.xml.Node

class ConfigService {
  def parseConfigXml(xmlString: String): Map[String, String] = {
    val xml = XML.loadString(xmlString)
    extractSettings(xml)
  }
  
  private def extractSettings(node: Node): Map[String, String] = {
    node match {
      case elem if elem.label == "configuration" =>
        elem.child.flatMap {
          case setting: scala.xml.Elem if setting.label == "setting" =>
            val key = setting.attribute("name").map(_.text).getOrElse("")
            val value = setting.text
            if (key.nonEmpty) Some(key -> value) else None
          case _ => None
        }.toMap
      case _ => Map.empty
    }
  }
  
  def parseConfigWithEntities(xmlString: String): Map[String, String] = {
    try {
      val xml = XML.loadString(xmlString)
      extractSettings(xml)
    } catch {
      case _: scala.xml.ParseError => Map.empty
    }
  }
}